@use '../core/tokens/m2-utils';
@use 'sass:map';

@function get-tokens($theme) {
  $system: m2-utils.get-system($theme);

  @return (
    base: (
      bottom-sheet-container-shape: 4px,
    ),
    color: (
      bottom-sheet-container-text-color: map.get($system, on-surface),
      bottom-sheet-container-background-color: map.get($system, surface),
    ),
    typography: (
      bottom-sheet-container-text-font: map.get($system, body-medium-font),
      bottom-sheet-container-text-line-height: map.get($system, body-medium-line-height),
      bottom-sheet-container-text-size: map.get($system, body-medium-size),
      bottom-sheet-container-text-tracking: map.get($system, body-medium-tracking),
      bottom-sheet-container-text-weight: map.get($system, body-medium-weight),
    ),
    density: (),
  );
}

@use '../m2/theming' as m2-theming;
@use '../m2/palette' as m2-palette;

// @deprecated Use `get-color-from-palette`.
@function color($palette, $hue: default, $opacity: null) {
  @return m2-theming.get-color-from-palette($palette, $hue, $opacity);
}

// @deprecated Use `get-contrast-color-from-palette`.
@function contrast($palette, $hue) {
  @return m2-theming.get-contrast-color-from-palette($palette, $hue);
}

// @deprecated Use `define-palette`.
@function palette($base-palette, $default: 500, $lighter: 100, $darker: 700, $text: $default) {
  @return m2-theming.define-palette($base-palette, $default, $lighter, $darker, $text);
}

// @deprecated Use `define-light-theme`.
@function dark-theme($primary, $accent: null, $warn: palette(m2-palette.$red-palette)) {
  @return m2-theming.define-dark-theme($primary, $accent, $warn);
}

// @deprecated Use `define-light-theme`.
@function light-theme($primary, $accent: null, $warn: palette(m2-palette.$red-palette)) {
  @return m2-theming.define-light-theme($primary, $accent, $warn);
}

// Mixin that resets user agent styles to make the form field behave consistently.
@mixin private-form-field-user-agent-overrides() {
  .mat-mdc-form-field-input-control {
    // Due to the native input masking these inputs can be slightly taller than
    // the plain text inputs. We normalize it by resetting the line height.
    &[type='date'],
    &[type='datetime'],
    &[type='datetime-local'],
    &[type='month'],
    &[type='week'],
    &[type='time'] {
      line-height: 1;
    }

    // Native datetime inputs have an element in the shadow DOM that makes them taller than
    // other inputs. These changes reset the user agent styles to make them consistent.
    // via https://8yd.no/article/date-input-height-in-safari
    &::-webkit-datetime-edit {
      line-height: 1;
      padding: 0;
      margin-bottom: -2px;
    }
  }
}

@use '../core/tokens/m2-utils';
@use 'sass:map';

@function get-tokens($theme) {
  $system: m2-utils.get-system($theme);

  @return (
    base: (),
    color: (),
    typography: (
      // TODO(crisbeto): other components have tokens for all typography dimensions.
      // Here we only set the font size to maintain the same appearance as the pre-tokens
      // theming API. Consider adding more tokens for letter spacing, font weight etc.
      grid-list-tile-header-primary-text-size: map.get($system, body-medium-size),
      grid-list-tile-header-secondary-text-size: map.get($system, body-small-size),
      grid-list-tile-footer-primary-text-size: map.get($system, body-medium-size),
      grid-list-tile-footer-secondary-text-size: map.get($system, body-small-size),
    ),
    density: (),
  );
}

@use 'sass:map';
@use '../core/theming/theming';
@use '../core/tokens/m2-utils';

@function get-tokens($theme) {
  $system: m2-utils.get-system($theme);
  $density-scale: theming.clamp-density(map.get($system, density-scale), -4);

  @return (
    base: (),
    color: (
      tree-container-background-color: map.get($system, surface),
      tree-node-text-color: map.get($system, on-surface),
    ),
    typography: (
      // TODO(crisbeto): provide tokens for line height and letter spacing
      tree-node-text-font: map.get($system, body-medium-font),
      tree-node-text-size: map.get($system, body-medium-size),
      tree-node-text-weight: map.get($system, body-medium-weight),),
    density: (
      tree-node-min-height: map.get((
        0: 48px,
        -1: 44px,
        -2: 40px,
        -3: 36px,
        -4: 28px,
      ), $density-scale)
    ),
  );
}

