@use "variables" as *;

.placeholder {
  display: inline-block;
  min-height: 1em;
  vertical-align: middle;
  cursor: wait;
  background-color: currentcolor;
  opacity: $placeholder-opacity-max;

  &.btn::before {
    display: inline-block;
    content: "";
  }
}

// Sizing
.placeholder-xs {
  min-height: .6em;
}

.placeholder-sm {
  min-height: .8em;
}

.placeholder-lg {
  min-height: 1.2em;
}

// Animation
.placeholder-glow {
  .placeholder {
    animation: placeholder-glow 2s ease-in-out infinite;
  }
}

@keyframes placeholder-glow {
  50% {
    opacity: $placeholder-opacity-min;
  }
}

.placeholder-wave {
  mask-image: linear-gradient(130deg, $black 55%, rgba(0, 0, 0, (1 - $placeholder-opacity-min)) 75%, $black 95%);
  mask-size: 200% 100%;
  animation: placeholder-wave 2s linear infinite;
}

@keyframes placeholder-wave {
  100% {
    mask-position: -200% 0%;
  }
}

@use "contrast-ratio" as *;

// We use this function only in variables.scss because recursive imports are not allowed in Sass anymore.

@function color-contrast-variables($background, $color-contrast-dark, $color-contrast-light, $white, $black, $min-contrast-ratio) {
  $foregrounds: $color-contrast-light, $color-contrast-dark, $white, $black;
  $max-ratio: 0;
  $max-ratio-color: null;

  @each $color in $foregrounds {
    $contrast-ratio: contrast-ratio($background, $color);
    @if $contrast-ratio >= $min-contrast-ratio {
      @return $color;
    } @else if $contrast-ratio > $max-ratio {
      $max-ratio: $contrast-ratio;
      $max-ratio-color: $color;
    }
  }

  @warn "Found no color leading to #{$min-contrast-ratio}:1 contrast ratio against #{$background}...";

  @return $max-ratio-color;
}

@use "sass:color";
@use "sass:math";

@function color-translucent($target-color, $alpha: .1, $bg-color: #fff) {
  @if color.alpha($target-color) < 1 {
    @return $target-color;
  }

  @if $alpha <= 0 or $alpha > 1 {
    @error "Alpha must be greater than 0 and less than or equal to 1.";
  }

  $r: math.div(
    color.channel($target-color, "red") - color.channel($bg-color, "red") * (1 - $alpha),
    $alpha
  );

  $g: math.div(
    color.channel($target-color, "green") - color.channel($bg-color, "green") * (1 - $alpha),
    $alpha
  );

  $b: math.div(
    color.channel($target-color, "blue") - color.channel($bg-color, "blue") * (1 - $alpha),
    $alpha
  );

  @if $r < 0 or $r > 255 or $g < 0 or $g > 255 or $b < 0 or $b > 255 {
    @error "Cannot reproduce #{$target-color} on #{$bg-color} with alpha #{$alpha}. Try a higher alpha.";
  }

  @return rgba(round($r), round($g), round($b), $alpha);
}

@import "./accordion-group";
@import "../accordion/accordion.md.vars";

// Material Design Accordion Group
// --------------------------------------------------

:host(.accordion-group-expand-inset) ::slotted(ion-accordion) {
  box-shadow: $accordion-md-box-shadow;
}

:host(.accordion-group-expand-inset) ::slotted(ion-accordion.accordion-expanding),
:host(.accordion-group-expand-inset) ::slotted(ion-accordion.accordion-expanded) {
  @include margin($accordion-md-expanded-margin, 0, $accordion-md-expanded-margin, 0);
  @include border-radius($accordion-md-border-radius, $accordion-md-border-radius, $accordion-md-border-radius, $accordion-md-border-radius);
}

:host(.accordion-group-expand-inset) ::slotted(ion-accordion.accordion-previous) {
  @include border-radius(null, null, $accordion-md-border-radius, $accordion-md-border-radius);
}

:host(.accordion-group-expand-inset) ::slotted(ion-accordion.accordion-next) {
  @include border-radius($accordion-md-border-radius, $accordion-md-border-radius, null, null);
}

:host(.accordion-group-expand-inset) ::slotted(ion-accordion):first-of-type {
  @include margin(0, 0, 0, 0);
}

@import "../../themes/ionic.globals";

// Datetime Button
// --------------------------------------------------

:host {
  display: flex;

  flex-wrap: wrap;

  align-items: center;

  justify-content: center;
}

:host button {
  @include border-radius(8px);
  @include margin(0px, 2px, 0px, 2px);

  position: relative;

  transition: 150ms color ease-in-out;

  border: none;

  background: var(--ion-color-step-300, var(--ion-background-color-step-300, #edeef0));

  color: $text-color;

  font-family: inherit;
  font-size: dynamic-font(16px);

  cursor: pointer;

  overflow: hidden;

  appearance: none;
}

:host(.time-active) #time-button,
:host(.date-active) #date-button {
  color: current-color(base);
}

:host(.datetime-button-disabled) {
  pointer-events: none;
}

:host(.datetime-button-disabled) button {
  opacity: 0.4;
}

@import "../../themes/ionic.globals";
@import "../../themes/ionic.mixins";

// Responsive Mixins
// --------------------------------------------------


// Creates a fixed width for the grid based on the screen size
// ---------------------------------------------------------------------------------

@mixin make-grid-widths($widths: $grid-widths, $breakpoints: $screen-breakpoints) {
  @each $breakpoint, $width in $widths {
    @include media-breakpoint-up($breakpoint, $breakpoints) {
      width: $width;
    }
  }

  max-width: 100%;
}


// Adds padding to the element based on breakpoints
// ---------------------------------------------------------------------------------

@mixin make-breakpoint-padding($paddings) {
  @each $breakpoint in map-keys($paddings) {
    @include media-breakpoint-up($breakpoint) {
      $padding: map-get($paddings, $breakpoint);

      @include padding($padding);
    }
  }
}

@import "./infinite-scroll-content.vars";

// Infinite Scroll Content
// --------------------------------------------------

ion-infinite-scroll-content {
  display: flex;

  flex-direction: column;
  justify-content: center;

  min-height: $infinite-scroll-content-min-height;

  text-align: center;

  user-select: none;
}

.infinite-loading {
  @include margin($infinite-scroll-loading-margin-top, $infinite-scroll-loading-margin-end, $infinite-scroll-loading-margin-bottom, $infinite-scroll-loading-margin-start);

  display: none;

  width: 100%;
}


.infinite-loading-text {
  @include margin($infinite-scroll-loading-text-margin-top, $infinite-scroll-loading-text-margin-end, $infinite-scroll-loading-text-margin-bottom, $infinite-scroll-loading-text-margin-start);
}



// Infinite Scroll Content States
// --------------------------------------------------
.infinite-scroll-loading ion-infinite-scroll-content > .infinite-loading {
  display: block;
}

@import "./loading";
@import "./loading.ios.vars";

// iOS Loading Indicator
// --------------------------------------------------

:host {
  --background: #{$loading-ios-background-color};
  --max-width: #{$loading-ios-max-width};
  --max-height: #{$loading-ios-max-height};
  --spinner-color: #{$loading-ios-spinner-color};
  --backdrop-opacity: var(--ion-backdrop-opacity, 0.3);

  color: $loading-ios-text-color;

  font-size: $loading-ios-font-size;
}

.loading-wrapper {
  @include border-radius($loading-ios-border-radius);
  @include padding($loading-ios-padding-top, $loading-ios-padding-end, $loading-ios-padding-bottom, $loading-ios-padding-start);
}


// iOS Translucent Loading
// -----------------------------------------

@supports (backdrop-filter: blur(0)) {
  :host(.loading-translucent) .loading-wrapper {
    background-color: $loading-ios-translucent-background-color;
    backdrop-filter: $loading-ios-translucent-filter;
  }
}


// iOS Loading Content
// -----------------------------------------

.loading-content {
  font-weight: $loading-ios-content-font-weight;
}

.loading-spinner + .loading-content {
  @include margin-horizontal(16px, null);
}

