// Circle badge icon with drop shadow for icons and logos

.CircleBadge {
  display: flex;
  align-items: center;
  justify-content: center;
  background-color: var(--bgColor-default, var(--color-canvas-default));
  border-radius: 50%;
  box-shadow: var(--shadow-resting-medium, var(--color-shadow-medium));
}

.CircleBadge-icon {
  max-width: 60% !important;
  height: auto !important;
  max-height: 55% !important;
}

// Small badge
.CircleBadge--small {
  width: 56px;
  height: 56px;
}

// Medium badge
.CircleBadge--medium {
  width: 96px;
  height: 96px;
}

// Large badge
.CircleBadge--large {
  width: 128px;
  height: 128px;
}

// Dashed line that connects badges..
// Wrap around 2 or more badges to create a horizonal line:

.DashedConnection {
  position: relative;

  &::before {
    position: absolute;
    top: 50%;
    left: 0;
    width: 100%;
    content: '';
    // stylelint-disable-next-line primer/borders
    border-bottom: 2px dashed var(--borderColor-default, var(--color-border-default));
  }

  .CircleBadge {
    position: relative;
  }
}

// Needs refactoring
// stylelint-disable selector-max-type
.markdown-body {
  // Tables
  table {
    display: block;
    width: 100%; // keep for backwards compatibility
    width: max-content;
    max-width: 100%;
    overflow: auto;
    font-variant: tabular-nums;

    th {
      // stylelint-disable-next-line primer/typography
      font-weight: $font-weight-bold;
    }

    th,
    td {
      // stylelint-disable-next-line primer/spacing
      padding: 6px 13px;
      // stylelint-disable-next-line primer/borders, primer/colors
      border: $border-width $border-style var(--borderColor-default, var(--color-border-default));
    }

    td {
      > :last-child {
        margin-bottom: 0;
      }
    }

    tr {
      background-color: var(--bgColor-default, var(--color-canvas-default));
      // stylelint-disable-next-line primer/borders, primer/colors
      border-top: $border-width $border-style var(--borderColor-muted, var(--color-border-muted));

      &:nth-child(2n) {
        background-color: var(--bgColor-muted, var(--color-canvas-subtle));
      }
    }

    img {
      background-color: transparent;
    }
  }
}

// Animation utilities for marketing

.hover-grow-mktg {
  // stylelint-disable-next-line declaration-property-value-no-unknown
  transition: transform 0.4s $ease-mktg;

  &:hover {
    transform: scale3d(1.025, 1.025, 1.025);
  }
}

// Animated arrow symbol, used in marketing links, buttons, etc.
.btn-mktg,
.link-mktg,
.arrow-target-mktg {
  .octicon {
    width: 1em;
    height: 1em;
  }

  .arrow-symbol-mktg {
    transition: transform 0.2s;
    transform: translateX(0);

    // stylelint-disable-next-line selector-max-type
    path:last-child {
      stroke-dasharray: 10;
      stroke-dashoffset: 10;
      transition: stroke-dashoffset 0.2s;
    }
  }

  @media screen and (prefers-reduced-motion: no-preference) {
    &:hover,
    &:focus {
      .arrow-symbol-mktg {
        transform: translateX(4px);

        // stylelint-disable-next-line selector-max-type, selector-max-specificity, max-nesting-depth
        path:last-child {
          stroke-dashoffset: 20;
        }
      }
    }

    &:active {
      .arrow-symbol-mktg {
        transform: translateX(6px);
      }
    }
  }
}

//
// Pager pagination
// --------------------------------------------------


.pager {
  padding-left: 0;
  margin: $line-height-computed 0;
  text-align: center;
  list-style: none;
  @include clearfix;
  li {
    display: inline;
    > a,
    > span {
      display: inline-block;
      padding: 5px 14px;
      background-color: $pager-bg;
      border: 1px solid $pager-border;
      border-radius: $pager-border-radius;
    }

    > a:hover,
    > a:focus {
      text-decoration: none;
      background-color: $pager-hover-bg;
    }
  }

  .next {
    > a,
    > span {
      float: right;
    }
  }

  .previous {
    > a,
    > span {
      float: left;
    }
  }

  .disabled {
    > a,
    > a:hover,
    > a:focus,
    > span {
      color: $pager-disabled-color;
      cursor: $cursor-disabled;
      background-color: $pager-bg;
    }
  }
}

//
// Thumbnails
// --------------------------------------------------


// Mixin and adjust the regular image class
.thumbnail {
  display: block;
  padding: $thumbnail-padding;
  margin-bottom: $line-height-computed;
  line-height: $line-height-base;
  background-color: $thumbnail-bg;
  border: 1px solid $thumbnail-border;
  border-radius: $thumbnail-border-radius;
  @include transition(border .2s ease-in-out);

  > img,
  a > img {
    @include img-responsive;
    margin-right: auto;
    margin-left: auto;
  }

  // [converter] extracted a&:hover, a&:focus, a&.active to a.thumbnail:hover, a.thumbnail:focus, a.thumbnail.active

  // Image captions
  .caption {
    padding: $thumbnail-caption-padding;
    color: $thumbnail-caption-color;
  }
}

// Add a hover state for linked versions only
a.thumbnail:hover,
a.thumbnail:focus,
a.thumbnail.active {
  border-color: $link-color;
}

// Base class
//
// Requires one of the contextual, color modifier classes for `color` and
// `background-color`.

.badge {
  // scss-docs-start badge-css-vars
  --#{$prefix}badge-padding-x: #{$badge-padding-x};
  --#{$prefix}badge-padding-y: #{$badge-padding-y};
  @include rfs($badge-font-size, --#{$prefix}badge-font-size);
  --#{$prefix}badge-font-weight: #{$badge-font-weight};
  --#{$prefix}badge-color: #{$badge-color};
  --#{$prefix}badge-border-radius: #{$badge-border-radius};
  // scss-docs-end badge-css-vars

  display: inline-block;
  padding: var(--#{$prefix}badge-padding-y) var(--#{$prefix}badge-padding-x);
  @include font-size(var(--#{$prefix}badge-font-size));
  font-weight: var(--#{$prefix}badge-font-weight);
  line-height: 1;
  color: var(--#{$prefix}badge-color);
  text-align: center;
  white-space: nowrap;
  vertical-align: baseline;
  @include border-radius(var(--#{$prefix}badge-border-radius));
  @include gradient-bg();

  // Empty badges collapse automatically
  &:empty {
    display: none;
  }
}

// Quick fix for badges in buttons
.btn .badge {
  position: relative;
  top: -1px;
}

