//
// Callouts
//

.bd-callout {
  --#{$prefix}link-color-rgb: var(--bd-callout-link);
  --#{$prefix}code-color: var(--bd-callout-code-color);

  padding: 1.25rem;
  margin-top: 1.25rem;
  margin-bottom: 1.25rem;
  color: var(--bd-callout-color, inherit);
  background-color: var(--bd-callout-bg, var(--bs-gray-100));
  border-left: .25rem solid var(--bd-callout-border, var(--bs-gray-300));

  h4 {
    margin-bottom: .25rem;
  }

  > :last-child {
    margin-bottom: 0;
  }

  + .bd-callout {
    margin-top: -.25rem;
  }

  .highlight {
    background-color: rgba($black, .05);
  }
}

// Variations
@each $variant in $bd-callout-variants {
  .bd-callout-#{$variant} {
    --bd-callout-color: var(--bs-#{$variant}-text-emphasis);
    --bd-callout-bg: var(--bs-#{$variant}-bg-subtle);
    --bd-callout-border: var(--bs-#{$variant}-border-subtle);
  }
}

@use "../../settings" as *;
@use "./icon" as *;
@use "../../functions" as *;
@use "./screen-reader" as *;

$external-link-size: 1.75ex;

$icon-object: (
  "name": "launch",
  "color": currentColor,
  "height": $external-link-size,
  "svg-height": 24,
  "svg-width": 24,
  "position-x": center,
  "position-y": center,
);

@mixin external-link($contrast-bg: "default") {
  display: inline;

  // Screen reader label
  &::before {
    @include sr-only;
    content: $theme-external-link-sr-label-tab-same;
  }

  &[target="_blank"]::before {
    @include sr-only;
    content: $theme-external-link-sr-label-tab-new;
  }

  &::after {
    @include add-color-icon($icon-object, $contrast-bg);
    content: "";
    display: inline;
    margin-top: 0.7ex;
    margin-left: 2px;
    padding-left: 1.75ex;
    vertical-align: middle;
  }
}

@use "../general/table" as *;
@use "../helpers/at-media" as *;

@mixin usa-table-styles {
  table {
    @include usa-table;
  }
  .usa-table--borderless {
    @include usa-table--borderless;
  }
  .usa-table--compact {
    @include usa-table--compact;
  }
  .usa-table--striped {
    @include usa-table--striped;
  }
  .usa-table--stacked {
    @include at-media-max("mobile-lg") {
      @include table-stacked-styles;
    }
  }
  .usa-table--stacked-header {
    @include at-media-max("mobile-lg") {
      @include table-stacked-styles;
      @include table-stacked-header-styles;
    }
  }
  .width-mobile {
    .usa-table--stacked {
      @include usa-table--stacked;
    }
    .usa-table--stacked-header {
      @include usa-table--stacked-header;
    }
  }
  .usa-table-container--scrollable {
    @include usa-table-container--scrollable;
  }
}
